// StateDrain halts the hart via the Debug Module and populates a
// hybrid_state_v1 with the architectural register file. Reuses
// ResumeDriver's DM register constants and DmiBus interface.

#pragma once

#include "hybrid/abstract_command.hpp"
#include "hybrid/dmi_poll.hpp"
#include "hybrid/resume_driver.hpp"
#include "hybrid/state_abi.h"

#include <algorithm>
#include <cstdint>

namespace hybrid
{

class StateDrain
{
public:
  using RD = ResumeDriver;

  explicit StateDrain(DmiBus& bus)
      : bus_{bus}
  {}

  // Drain x1..x31 + PC. FP/CSR/V slots remain zero; merge them in via
  // drain_with_passthrough when the QEMU 1 snapshot is available.
  auto drain() -> hybrid_state_v1
  {
    bus_.write(RD::kDmcontrol, RD::kDmcontrolDmactive);
    bus_.write(RD::kDmcontrol, RD::kDmcontrolDmactive | RD::kDmcontrolHaltreq);
    poll_until_set(bus_, RD::kDmstatus, RD::kDmstatusAllhalted,
                   "StateDrain halt");

    hybrid_state_v1 state{};
    state.magic   = HYBRID_STATE_MAGIC;
    state.version = HYBRID_STATE_VERSION;
    state.flags   = HYBRID_FLAG_RV64;
    state.priv    = 3;

    for (uint16_t i = 1; i < 32; ++i)
      state.gpr[i] = read_64bit_register(regno_gpr(i));

    state.pc = read_64bit_register(regno_csr(RD::kCsrDpc));
    return state;
  }

  // Returns the input snapshot with x1..x31 and PC overwritten by a fresh
  // DM read. When HYBRID_FLAG_FP is set, also freshly reads f0..f31 so
  // post-vsim FP modifications are captured (otherwise the stale QEMU 1
  // snapshot leaks through to QEMU 2). When HYBRID_FLAG_V is set, also
  // freshly reads the six V CSRs (vstart/vxsat/vxrm/vcsr/vtype/vl); vlenb
  // and vreg remain pass-through (read-only / too large for DM).
  // mcycle/minstret are always refreshed (F-T2.4): the vsim phase's
  // contribution would otherwise be discarded as the passthrough preserves
  // QEMU1's pre-handoff value.
  auto drain_with_passthrough(const hybrid_state_v1& input) -> hybrid_state_v1
  {
    auto state       = input;
    const auto fresh = drain();
    std::copy(std::begin(fresh.gpr) + 1, std::end(fresh.gpr),
              std::begin(state.gpr) + 1);
    state.pc = fresh.pc;

    if (input.flags & HYBRID_FLAG_FP) {
      for (uint16_t i = 0; i < 32; ++i)
        state.fpr[i] = read_64bit_register(regno_fpr(i));
    }

    if (input.flags & HYBRID_FLAG_V) {
      state.vstart = read_64bit_register(regno_csr(RD::kCsrVstart));
      state.vxsat  = read_64bit_register(regno_csr(RD::kCsrVxsat));
      state.vxrm   = read_64bit_register(regno_csr(RD::kCsrVxrm));
      state.vcsr   = read_64bit_register(regno_csr(RD::kCsrVcsr));
      state.vtype  = read_64bit_register(regno_csr(RD::kCsrVtype));
      state.vl     = read_64bit_register(regno_csr(RD::kCsrVl));
    }

    state.mcycle   = read_64bit_register(regno_csr(RD::kCsrMcycle));
    state.minstret = read_64bit_register(regno_csr(RD::kCsrMinstret));

    return state;
  }

private:
  auto read_64bit_register(uint16_t regno) -> uint64_t
  {
    bus_.write(RD::kCommand, access_register_command(regno, AarSize::Bits64,
                                                     /*write=*/false));
    poll_until_clear(bus_, RD::kAbstractcs, RD::kAbstractcsBusy,
                     "StateDrain read_register");
    // If the hardware DM does not implement Abstract access for this
    // register, cmderr is set sticky and DATA0/DATA1 hold stale bytes.
    // Clear the error and report 0 for that field so the next read can
    // proceed - a missing CSR mirrors as zero rather than corrupting the
    // adjacent slot.
    const auto status = bus_.read(RD::kAbstractcs);
    if ((status & RD::kAbstractcsCmderrMask) != 0u) {
      bus_.write(RD::kAbstractcs, RD::kAbstractcsCmderrMask);
      return 0u;
    }
    const uint64_t lo = bus_.read(RD::kData0);
    const uint64_t hi = bus_.read(RD::kData1);
    return lo | (hi << 32);
  }

  DmiBus& bus_;
};

}  // namespace hybrid

// V-register transport via shared scratch RAM. The vsim Debug Module
// abstract-command space does not allocate slots for v0..v31 (RISC-V Debug
// Spec leaves V to optional Program Buffer or implementation-specific
// extensions), and the AX45MPV CPU wrapper does not export a DPI probe for
// the V regfile. As a stop-gap that keeps Phase 5 (DPI / PB) deferred while
// still letting C-level RVV fixtures round-trip:
//
//   - On resume from QEMU 1, vsim copies state.vreg[] into a fixed scratch
//     region of guest RAM (kVScratchGpa). The fixture's vsim-phase prologue
//     issues `vle8.v vN, (t0)` against that region to repopulate v0..v31.
//   - Before the vsim->QEMU2 drain trigger, the fixture issues `vse8.v vN,
//     (t0)` to write the (possibly mutated) regfile back to the same region.
//     vsim's StateDrain side reads the scratch bytes into state.vreg[] so
//     qemu_handback can ship them to QEMU 2 via the existing gdbstub P
//     packets.
//
// The contract is fixture-aware: any program that wants V state preserved
// across the vsim boundary must perform the load/store at the boundaries.
// rt_c_v_regs.c demonstrates the pattern. Phase 5 will replace this with a
// transparent mechanism (PB or DPI) so benchmark binaries don't need to be
// modified.
//
// Pure logic: no SystemC, no DMI bus. Easy to unit-test.

#pragma once

#include "hybrid/state_abi.h"

#include <cstddef>
#include <cstdint>
#include <cstring>
#include <span>
#include <stdexcept>

namespace hybrid
{

// Reserved scratch slot inside the shared mmap. Sits well above the C
// runtime's _stack (rt_c.ld places it at RAM_BASE + 0x700000), giving the
// stack ~9 MiB of headroom before colliding with this 2 KiB region. On
// `-M andes_ae350` RAM is at 0x00000000 and the GPA is 0x00FF0000; on
// `-M virt` it would be 0x80FF0000. The chosen address is RAM_BASE +
// 0xFF0000, an offset that has to match the `li t0, ...` constant in the
// fixture's runtime/v_regfile_xfer.c.
inline constexpr uint64_t kVScratchGpa = 0x00FF0000ull;

// Total scratch bytes needed: 32 V regs × HYBRID_VLEN_BYTES_MAX. Sized to
// the maximum supported VLEN; the actual per-reg byte count is `vlenb`.
inline constexpr std::size_t kVScratchBytes =
  static_cast<std::size_t>(32) * HYBRID_VLEN_BYTES_MAX;

namespace detail
{

// Translate scratch GPA into a byte offset inside a RAM span whose first
// byte sits at `ram_base`. Throws if the scratch region falls outside the
// supplied span (i.e. the caller passed a too-small RAM mapping).
inline auto scratch_offset(std::size_t ram_size, uint64_t ram_base)
  -> std::size_t
{
  if (kVScratchGpa < ram_base)
    throw std::runtime_error(
      "v_regfile_xfer: scratch GPA below RAM base");
  const auto off = static_cast<std::size_t>(kVScratchGpa - ram_base);
  if (off + kVScratchBytes > ram_size)
    throw std::runtime_error(
      "v_regfile_xfer: scratch region exceeds RAM span");
  return off;
}

}  // namespace detail

// Copy state.vreg[] into ram[scratch_offset .. scratch_offset+kVScratchBytes].
// Called just before vsim resumes the hart so the fixture can vle8.v from
// scratch and pick up QEMU 1's V values.
inline void stage_v_to_scratch(const hybrid_state_v1& state,
                               std::span<uint8_t> ram,
                               uint64_t ram_base)
{
  const auto off = detail::scratch_offset(ram.size(), ram_base);
  std::memcpy(ram.data() + off, state.vreg, kVScratchBytes);
}

// Copy ram[scratch_offset .. +kVScratchBytes] into state.vreg[]. Called
// inside the vsim drain path after the fixture's prologue vse8.v has
// settled the (possibly mutated) regfile bytes into RAM.
inline void read_v_from_scratch(hybrid_state_v1& state,
                                std::span<const uint8_t> ram,
                                uint64_t ram_base)
{
  const auto off = detail::scratch_offset(ram.size(), ram_base);
  std::memcpy(state.vreg, ram.data() + off, kVScratchBytes);
}

}  // namespace hybrid

