#pragma once

#include <cstdint>

namespace hybrid {

enum class AarSize : uint8_t
{
  Bits32 = 2,
  Bits64 = 3,
  Bits128 = 4,
};

constexpr auto regno_csr(uint16_t csr) -> uint16_t { return csr; }
constexpr auto regno_gpr(uint16_t i) -> uint16_t { return 0x1000u + i; }
constexpr auto regno_fpr(uint16_t i) -> uint16_t { return 0x1020u + i; }
constexpr auto regno_vector(uint16_t i) -> uint16_t { return 0x1040u + i; }

constexpr auto access_register_command(uint16_t regno, AarSize size, bool write,
                                       bool postexec = false) -> uint32_t
{
  uint32_t cmd = 0;
  cmd |= (uint32_t(size) & 0x7u) << 20;
  if (postexec) cmd |= 1u << 18;
  cmd |= 1u << 17;
  if (write) cmd |= 1u << 16;
  cmd |= regno;
  return cmd;
}

}  // namespace hybrid

